# setup-sprint-0.ps1
# Reconstitue le pack Sprint 0 de Decibel Dash dans le dossier courant.
# Usage : depuis le dossier racine du repo (vide), lancer :
#   .\setup-sprint-0.ps1

$ErrorActionPreference = "Stop"

Write-Host "Setup Sprint 0 - Decibel Dash" -ForegroundColor Cyan
Write-Host "Cible : $PWD" -ForegroundColor Gray
Write-Host ""

$files = @(
    @{ Path = '.github\workflows\ci.yml'; B64 = '' },
    @{ Path = '.gitignore'; B64 = '' },
    @{ Path = '.prettierignore'; B64 = 'ZGlzdApub2RlX21vZHVsZXMKY292ZXJhZ2UKcG5wbS1sb2NrLnlhbWwKcHVibGljL21vZGVsCioubWluLioK' },
    @{ Path = '.prettierrc'; B64 = 'ewogICJzZW1pIjogdHJ1ZSwKICAic2luZ2xlUXVvdGUiOiB0cnVlLAogICJ0cmFpbGluZ0NvbW1hIjogImFsbCIsCiAgInByaW50V2lkdGgiOiAxMDAsCiAgInRhYldpZHRoIjogMiwKICAidXNlVGFicyI6IGZhbHNlLAogICJhcnJvd1BhcmVucyI6ICJhbHdheXMiLAogICJlbmRPZkxpbmUiOiAibGYiCn0K' },
    @{ Path = 'README.md'; B64 = '' },
    @{ Path = 'eslint.config.js'; B64 = '' },
    @{ Path = 'index.html'; B64 = '' },
    @{ Path = 'package.json'; B64 = '' },
    @{ Path = 'src\App.tsx'; B64 = '' },
    @{ Path = 'src\game\HelloPixi.tsx'; B64 = '' },
    @{ Path = 'src\game\usePixiApp.ts'; B64 = '' },
    @{ Path = 'src\main.tsx'; B64 = '' },
    @{ Path = 'src\styles\index.css'; B64 = '' },
    @{ Path = 'src\test\setup.ts'; B64 = 'Ly8gU2V0dXAgZ2xvYmFsIHBvdXIgVml0ZXN0IChqc2RvbSkKLy8gQWpvdXRlIGljaSBsZXMgcG9seWZpbGxzL21vY2tzIGdsb2JhdXggcXVhbmQgb24gYXR0YXF1ZXJhIGxlcyB0ZXN0cyBhdWRpby4KLy8gUG91ciBTcHJpbnQgMCA6IGp1c3RlIHMnYXNzdXJlciBxdWUgbCdlbnZpcm9ubmVtZW50IGNoYXJnZS4KCmV4cG9ydCB7fTsK' },
    @{ Path = 'src\test\smoke.test.ts'; B64 = '' },
    @{ Path = 'tsconfig.app.json'; B64 = '' },
    @{ Path = 'tsconfig.json'; B64 = 'ewogICJmaWxlcyI6IFtdLAogICJyZWZlcmVuY2VzIjogWwogICAgeyAicGF0aCI6ICIuL3RzY29uZmlnLmFwcC5qc29uIiB9LAogICAgeyAicGF0aCI6ICIuL3RzY29uZmlnLm5vZGUuanNvbiIgfQogIF0KfQo=' },
    @{ Path = 'tsconfig.node.json'; B64 = '' },
    @{ Path = 'vite.config.ts'; B64 = '' },
    @{ Path = 'vitest.config.ts'; B64 = '' }
)

$created = 0
foreach ($f in $files) {
    $fullPath = Join-Path $PWD $f.Path
    $dir = Split-Path $fullPath -Parent
    if (-not (Test-Path $dir)) {
        New-Item -ItemType Directory -Path $dir -Force | Out-Null
    }
    $bytes = [Convert]::FromBase64String($f.B64)
    [IO.File]::WriteAllBytes($fullPath, $bytes)
    Write-Host "  + $($f.Path)" -ForegroundColor Green
    $created++
}

Write-Host ""
Write-Host "$created fichiers créés." -ForegroundColor Cyan
Write-Host ""
Write-Host "Prochaine étape :" -ForegroundColor Yellow
Write-Host "  pnpm install" -ForegroundColor White
Write-Host "  pnpm dev" -ForegroundColor White
